class ElasticsearchLogHandler(logging.Handler):
    def __init__(self, app: ElasticsearchApp, service: str, environment: str = "development") -> None:
        super().__init__()
        self.app = app
        self.service = service
        self.environment = environment

    def emit(self, record: logging.LogRecord) -> None:
        try:
            fields = {
                "module": record.module,
                "function": record.funcName,
                "line": record.lineno,
                "process": record.process,
                "thread": record.thread,
                "pathname": record.pathname,
            }
            if hasattr(record, "extra_fields") and isinstance(record.extra_fields, dict):
                fields.update(record.extra_fields)

            self.app.index_log(
                level=record.levelname,
                service=self.service,
                message=record.getMessage(),
                logger_name=record.name,
                environment=self.environment,
                fields=fields,
                timestamp=datetime.fromtimestamp(record.created, tz=timezone.utc),
            )
        except Exception:
            self.handleError(record)


def print_json(data: Any) -> None:
    print(json.dumps(data, indent=2, default=str))


def demo() -> None:
    app = ElasticsearchApp()
    if not app.ping():
        raise RuntimeError("Unable to connect to Elasticsearch at localhost:9200")

    app.ensure_indices()

    app.index_document(
        title="Elasticsearch Full Text Search",
        content="Elasticsearch provides distributed full-text search and analytics capabilities.",
        tags=["search", "elasticsearch", "analytics"],
        author="platform-team",
        metadata={"category": "guide", "version": 1},
    )

    app.bulk_index_documents(
        [
            {
                "title": "Centralized Logging Platform",
                "content": "A centralized logging platform helps aggregate logs from multiple services.",
                "tags": ["logging", "observability"],
                "author": "ops-team",
                "metadata": {"priority": "high"},
            },
            {
                "title": "Search Relevance Tuning",
                "content": "Boosting fields and analyzers improve search relevance.",
                "tags": ["search", "relevance"],
                "author": "search-team",
                "metadata": {"priority": "medium"},
            },
        ]
    )

    doc_results = app.search_documents(query="centralized logging search", size=5)
    print_json(doc_results)

    app.index_log(
        level="INFO",
        service="api-gateway",
        message="Gateway started successfully",
        fields={"port": 8080, "region": "us-east-1"},
    )
    app.index_log(
        level="ERROR",
        service="api-gateway",
        message="Upstream service timeout",
        fields={"timeout_ms": 3000, "upstream": "user-service"},
    )
    app.bulk_index_logs(
        [
            {
                "level": "WARN",
                "service": "user-service",
                "message": "Slow database query detected",
                "fields": {"duration_ms": 1200, "query": "SELECT * FROM users"},
            },
            {
                "level": "INFO",
                "service": "user-service",
                "message": "User profile fetched",
                "fields": {"user_id": "u-123"},
            },
        ]
    )

    log_results = app.search_logs(query="timeout", service="api-gateway", size=10)
    print_json(log_results)

    start = datetime.now(timezone.utc) - timedelta(days=1)
    end = datetime.now(timezone.utc) + timedelta(minutes=1)
    agg_results = app.aggregate_logs(start_time=start, end_time=end, interval="30m")
    print_json(agg_results)

    logger = app.setup_python_logging(service="demo-service", environment="development")
    logger.info("Application logger connected to Elasticsearch")
    logger.error("Sample error event", extra={"extra_fields": {"request_id": "req-001", "component": "demo"}})

    time.sleep(1)
    recent_logs = app.search_logs(service="demo-service", size=5)
    print_json(recent_logs)


if __name__ == "__main__":
    demo()